&= \frac{(18)!}{18!}\left(\sum_{n = 0}^{10}\frac{1}{n!(18 - n)!} - 2\right)\\
&= \frac{1}{18!}\left(\sum_{n = 0}^{18}\frac{1}{n!(18 - n)!} - 2\right)\\
&= \frac{2^{18} - 2}{18!}
\end{align*}

